import{_ as a,o as r,c as t,a2 as n}from"./chunks/framework.C7GIOALF.js";const f=JSON.parse('{"title":"Archenemy","description":"","frontmatter":{},"headers":[],"relativePath":"formats/archenemy/index.md","filePath":"formats/archenemy/index.md","lastUpdated":1782025909000}'),o={name:"formats/archenemy/index.md"};function i(s,e,h,c,l,m){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="archenemy" tabindex="-1">Archenemy <a class="header-anchor" href="#archenemy" aria-label="Permalink to &quot;Archenemy&quot;">​</a></h1><p>Archenemy is an official multiplayer Magic format where one player becomes the villain and fights a team of heroes. Wizards describes it as one archenemy player facing three or more players on a team, with the archenemy using both a normal deck and a separate scheme deck. <a href="https://magic.wizards.com/en/formats/archenemy" target="_blank" rel="noreferrer">Source: Wizards Archenemy format page</a>.</p><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><ul><li>One player is the <strong>archenemy</strong>.</li><li>The other players form a team against the archenemy.</li><li>Each player still brings a normal Magic deck.</li><li>The archenemy also brings a <strong>scheme deck</strong>.</li><li>At the beginning of the archenemy&#39;s first main phase each turn, they reveal the top scheme and set it in motion.</li><li>Schemes create big villain moments: extra turns, board pressure, resource swings, punishments for the heroes, or other dramatic effects.</li></ul><h2 id="standard-archenemy" tabindex="-1">Standard Archenemy <a class="header-anchor" href="#standard-archenemy" aria-label="Permalink to &quot;Standard Archenemy&quot;">​</a></h2><p>In the traditional version, the archenemy uses a normal 60-card-or-larger deck plus a scheme deck of at least twenty oversized scheme cards. The hero team also uses normal 60-card-or-larger decks. <a href="https://magic.wizards.com/en/formats/archenemy" target="_blank" rel="noreferrer">Source: Wizards Archenemy format page</a>.</p><p>The usual setup is one archenemy against three or more heroes. The archenemy starts with more life than a normal player, goes first, and still draws on their first turn. The heroes each have their own life total, but they coordinate as a team. <a href="https://magic.wizards.com/en/formats/archenemy" target="_blank" rel="noreferrer">Source: Wizards Archenemy format page</a>.</p><h2 id="archenemy-commander" tabindex="-1">Archenemy Commander <a class="header-anchor" href="#archenemy-commander" aria-label="Permalink to &quot;Archenemy Commander&quot;">​</a></h2><p>Archenemy also works naturally as a Commander night format. In Archenemy Commander, the archenemy uses a Commander deck and a scheme deck of at least ten unique oversized scheme cards. The archenemy starts with a higher life total than in regular Archenemy, making the game feel closer to a Commander boss fight. <a href="https://magic.wizards.com/en/formats/archenemy-commander" target="_blank" rel="noreferrer">Source: Wizards Archenemy Commander format page</a>.</p><p>This is especially useful for boxed game nights because the box can include one villain deck, one scheme deck, and several hero decks designed to fight it.</p><h2 id="why-it-works-for-game-night" tabindex="-1">Why It Works For Game Night <a class="header-anchor" href="#why-it-works-for-game-night" aria-label="Permalink to &quot;Why It Works For Game Night&quot;">​</a></h2><ul><li>It gives one player permission to be theatrical and overpowered.</li><li>It creates an easy cooperative table structure.</li><li>Scheme cards make the game feel different from normal multiplayer without requiring every player to learn a new deck.</li><li>A prebuilt box can tune the villain deck, hero decks, and scheme deck together.</li></ul><h2 id="boxed-set-notes" tabindex="-1">Boxed-Set Notes <a class="header-anchor" href="#boxed-set-notes" aria-label="Permalink to &quot;Boxed-Set Notes&quot;">​</a></h2><p>An Archenemy box should probably include:</p><ul><li>One archenemy deck.</li><li>One scheme deck.</li><li>Two to four hero decks.</li><li>A quick reference for scheme timing.</li><li>Difficulty notes for changing the number of heroes or swapping schemes.</li><li>Optional achievement or campaign rules if the box is meant to be replayed.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://magic.wizards.com/en/formats/archenemy" target="_blank" rel="noreferrer">MTG Archenemy Format</a></li><li><a href="https://magic.wizards.com/en/formats/archenemy-commander" target="_blank" rel="noreferrer">MTG Archenemy Commander Format</a></li><li><a href="https://magic.wizards.com/en/news/feature/archenemy-rules-revealed-2010-05-17" target="_blank" rel="noreferrer">Archenemy Rules Revealed</a></li></ul>',17)])])}const u=a(o,[["render",i]]);export{f as __pageData,u as default};
